INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('46:35', 46, 35, 26, 506, 4545, 'فَاصْبِرْ كَمَا صَبَرَ اُولُوا الْعَزْمِ مِنَ الرُّسُلِ وَلَا تَسْتَعْجِلْ لَّهُمْ ۗ كَاَنَّهُمْ يَوْمَ يَرَوْنَ مَا يُوْعَدُوْنَۙ  لَمْ يَلْبَثُوْٓا اِلَّا سَاعَةً مِّنْ نَّهَارٍ ۗ بَلٰغٌ ۚفَهَلْ يُهْلَكُ اِلَّا الْقَوْمُ الْفٰسِقُوْنَ ࣖ', 'Maka, bersabarlah engkau (Nabi Muhammad) sebagaimana ululazmi (orang-orang yang memiliki keteguhan hati) dari kalangan para rasul telah bersabar dan janganlah meminta agar azab disegerakan untuk mereka. Pada hari ketika melihat azab yang dijanjikan, seolah-olah mereka hanya tinggal (di dunia) sesaat saja pada siang hari. (Nasihatmu itu) merupakan peringatan (dari Allah). Maka, tidak ada yang dibinasakan kecuali kaum yang fasik.', '', 'https://everyayah.com/data/Alafasy_128kbps/046035.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('47:1', 47, 1, 26, 507, 4546, 'اَلَّذِيْنَ كَفَرُوْا وَصَدُّوْا عَنْ سَبِيْلِ اللّٰهِ اَضَلَّ اَعْمَالَهُمْ ', ' Orang-orang yang kufur dan menghalang-halangi (manusia) dari jalan Allah, Dia akan menggugurkan amal-amal mereka.', '', 'https://everyayah.com/data/Alafasy_128kbps/047001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('47:2', 47, 2, 26, 507, 4547, 'وَالَّذِيْنَ اٰمَنُوْا وَعَمِلُوا الصّٰلِحٰتِ وَاٰمَنُوْا بِمَا نُزِّلَ عَلٰى مُحَمَّدٍ وَّهُوَ الْحَقُّ مِنْ رَّبِّهِمْ ۚ كَفَّرَ عَنْهُمْ سَيِّاٰتِهِمْ وَاَصْلَحَ بَالَهُمْ ', 'Orang-orang yang beriman, beramal saleh, dan beriman pada apa yang diturunkan kepada (Nabi) Muhammad bahwa ia merupakan kebenaran dari Tuhan mereka, Allah menghapuskan kesalahan-kesalahan mereka dan memperbaiki keadaannya.', '', 'https://everyayah.com/data/Alafasy_128kbps/047002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('47:3', 47, 3, 26, 507, 4548, 'ذٰلِكَ بِاَنَّ الَّذِيْنَ كَفَرُوا اتَّبَعُوا الْبَاطِلَ وَاَنَّ الَّذِيْنَ اٰمَنُوا اتَّبَعُوا الْحَقَّ مِنْ رَّبِّهِمْ ۗ كَذٰلِكَ يَضْرِبُ اللّٰهُ لِلنَّاسِ اَمْثَالَهُمْ ', ' (Hal) itu (terjadi) karena sesungguhnya orang-orang yang kufur mengikuti kebatilan, sedangkan orang-orang yang beriman mengikuti kebenaran dari Tuhan mereka. Demikianlah Allah membuat perumpamaan-perumpamaan mereka kepada manusia.', '', 'https://everyayah.com/data/Alafasy_128kbps/047003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('47:4', 47, 4, 26, 507, 4549, 'فَاِذَا لَقِيْتُمُ الَّذِيْنَ كَفَرُوْا فَضَرْبَ الرِّقَابِۗ حَتّٰٓى اِذَآ اَثْخَنْتُمُوْهُمْ فَشُدُّوا الْوَثَاقَۖ فَاِمَّا مَنًّاۢ بَعْدُ وَاِمَّا فِدَاۤءً حَتّٰى تَضَعَ الْحَرْبُ اَوْزَارَهَا ەۛ ذٰلِكَ ۛ وَلَوْ يَشَاۤءُ اللّٰهُ لَانْتَصَرَ مِنْهُمْ وَلٰكِنْ لِّيَبْلُوَا۟ بَعْضَكُمْ بِبَعْضٍۗ وَالَّذِيْنَ قُتِلُوْا فِيْ سَبِيْلِ اللّٰهِ فَلَنْ يُّضِلَّ اَعْمَالَهُمْ ', ' Maka, apabila kamu bertemu (di medan perang) dengan orang-orang yang kufur, tebaslah batang leher mereka. Selanjutnya, apabila kamu telah mengalahkan mereka, tawanlah mereka. Setelah itu, kamu boleh membebaskan mereka atau menerima tebusan. (Hal itu berlaku) sampai perang selesai. Demikianlah (hukum Allah tentang mereka). Sekiranya Allah menghendaki, niscaya Dia menolong (kamu) dari mereka (tanpa perang). Akan tetapi, Dia hendak menguji sebagian kamu dengan sebagian yang lain. Orang-orang yang gugur di jalan Allah, Dia tidak menyia-nyiakan amal-amalnya.', '', 'https://everyayah.com/data/Alafasy_128kbps/047004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('47:5', 47, 5, 26, 507, 4550, 'سَيَهْدِيْهِمْ وَيُصْلِحُ بَالَهُمْۚ', ' Dia (Allah) akan memberikan petunjuk kepada mereka, memperbaiki keadaannya,', '', 'https://everyayah.com/data/Alafasy_128kbps/047005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('47:6', 47, 6, 26, 507, 4551, 'وَيُدْخِلُهُمُ الْجَنَّةَ عَرَّفَهَا لَهُمْ ', 'dan memasukkannya ke dalam surga yang telah diperkenalkan-Nya kepada mereka.', '', 'https://everyayah.com/data/Alafasy_128kbps/047006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('47:7', 47, 7, 26, 507, 4552, 'يٰٓاَيُّهَا الَّذِيْنَ اٰمَنُوْٓا اِنْ تَنْصُرُوا اللّٰهَ يَنْصُرْكُمْ وَيُثَبِّتْ اَقْدَامَكُمْ ', ' Wahai orang-orang yang beriman, jika kamu menolong (agama) Allah, niscaya Dia akan menolongmu dan meneguhkan kedudukanmu.', '', 'https://everyayah.com/data/Alafasy_128kbps/047007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('47:8', 47, 8, 26, 507, 4553, 'وَالَّذِيْنَ كَفَرُوْا فَتَعْسًا لَّهُمْ وَاَضَلَّ اَعْمَالَهُمْ ', ' (Sebaliknya,) orang-orang yang kufur, maka kecelakaanlah bagi mereka dan Dia (Allah) membatalkan amal-amalnya.', '', 'https://everyayah.com/data/Alafasy_128kbps/047008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('47:9', 47, 9, 26, 507, 4554, 'ذٰلِكَ بِاَنَّهُمْ كَرِهُوْا مَآ اَنْزَلَ اللّٰهُ فَاَحْبَطَ اَعْمَالَهُمْ ', ' Hal itu (terjadi) karena mereka membenci apa yang diturunkan Allah (Al-Qur’an) sehingga Dia menggugurkan amal-amalnya.', '', 'https://everyayah.com/data/Alafasy_128kbps/047009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('47:10', 47, 10, 26, 507, 4555, '۞ اَفَلَمْ يَسِيْرُوْا فِى الْاَرْضِ فَيَنْظُرُوْا كَيْفَ كَانَ عَاقِبَةُ الَّذِيْنَ مِنْ قَبْلِهِمْ ۗ دَمَّرَ اللّٰهُ عَلَيْهِمْ ۖوَلِلْكٰفِرِيْنَ اَمْثَالُهَا ', ' Maka, apakah mereka tidak mengadakan perjalanan di bumi sehingga dapat memperhatikan bagaimana kesudahan orang-orang yang sebelum mereka? Allah telah membinasakan mereka dan orang-orang kafir akan menerima (nasib) yang serupa.', '', 'https://everyayah.com/data/Alafasy_128kbps/047010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('47:11', 47, 11, 26, 507, 4556, 'ذٰلِكَ بِاَنَّ اللّٰهَ مَوْلَى الَّذِيْنَ اٰمَنُوْا وَاَنَّ الْكٰفِرِيْنَ لَا مَوْلٰى لَهُمْ ࣖ', 'Hal itu (terjadi) karena Allah pelindung bagi orang-orang yang beriman, sedangkan orang-orang kafir tidak mempunyai pelindung.', '', 'https://everyayah.com/data/Alafasy_128kbps/047011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('47:12', 47, 12, 26, 508, 4557, 'اِنَّ اللّٰهَ يُدْخِلُ الَّذِيْنَ اٰمَنُوْا وَعَمِلُوا الصّٰلِحٰتِ جَنّٰتٍ تَجْرِيْ مِنْ تَحْتِهَا الْاَنْهٰرُ ۗوَالَّذِيْنَ كَفَرُوْا يَتَمَتَّعُوْنَ وَيَأْكُلُوْنَ كَمَا تَأْكُلُ الْاَنْعَامُ وَالنَّارُ مَثْوًى لَّهُمْ ', 'Sesungguhnya Allah akan memasukkan orang-orang yang beriman dan beramal saleh ke dalam surga yang mengalir di bawahnya sungai-sungai. Adapun orang-orang yang kufur bersenang-senang dan makan-makan (di dunia) seperti halnya hewan-hewan. Nerakalah tempat tinggal bagi mereka.', '', 'https://everyayah.com/data/Alafasy_128kbps/047012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('47:13', 47, 13, 26, 508, 4558, 'وَكَاَيِّنْ مِّنْ قَرْيَةٍ هِيَ اَشَدُّ قُوَّةً مِّنْ قَرْيَتِكَ الَّتِيْٓ اَخْرَجَتْكَۚ اَهْلَكْنٰهُمْ فَلَا نَاصِرَ لَهُمْ ', ' Betapa banyak negeri yang (penduduknya) lebih kuat daripada (penduduk) negerimu (Nabi Muhammad) yang telah mengusirmu itu. Kami telah membinasakan mereka. Tidak ada seorang pun yang menjadi penolong mereka.', '', 'https://everyayah.com/data/Alafasy_128kbps/047013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('47:14', 47, 14, 26, 508, 4559, 'اَفَمَنْ كَانَ عَلٰى بَيِّنَةٍ مِّنْ رَّبِّهٖ كَمَنْ زُيِّنَ لَهٗ سُوْۤءُ عَمَلِهٖ وَاتَّبَعُوْٓا اَهْوَاۤءَهُمْ ', ' Apakah orang yang berpegang teguh pada keterangan yang datang dari Tuhannya sama dengan orang yang perbuatan buruknya dijadikan terasa indah baginya dan mengikuti hawa nafsunya?', '', 'https://everyayah.com/data/Alafasy_128kbps/047014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('47:15', 47, 15, 26, 508, 4560, 'مَثَلُ الْجَنَّةِ الَّتِيْ وُعِدَ الْمُتَّقُوْنَ ۗفِيْهَآ اَنْهٰرٌ مِّنْ مَّاۤءٍ غَيْرِ اٰسِنٍۚ وَاَنْهٰرٌ مِّنْ لَّبَنٍ لَّمْ يَتَغَيَّرْ طَعْمُهٗ ۚوَاَنْهٰرٌ مِّنْ خَمْرٍ لَّذَّةٍ لِّلشّٰرِبِيْنَ ەۚ وَاَنْهٰرٌ مِّنْ عَسَلٍ مُّصَفًّى ۗوَلَهُمْ فِيْهَا مِنْ كُلِّ الثَّمَرٰتِ وَمَغْفِرَةٌ مِّنْ رَّبِّهِمْ ۗ كَمَنْ هُوَ خَالِدٌ فِى النَّارِ وَسُقُوْا مَاۤءً حَمِيْمًا فَقَطَّعَ اَمْعَاۤءَهُمْ', ' Perumpamaan surga yang dijanjikan kepada orang-orang yang bertakwa (adalah bahwa) di dalamnya ada sungai-sungai yang airnya tidak payau, sungai-sungai air susu yang rasanya tidak berubah, sungai-sungai khamar yang lezat bagi peminumnya, dan sungai-sungai madu yang murni. Di dalamnya mereka memperoleh segala macam buah dan ampunan dari Tuhan mereka. (Apakah orang yang memperoleh kenikmatan surga) sama dengan orang yang kekal dalam neraka dan diberi minuman dengan air yang mendidih sehingga usus mereka terpotong-potong?', '', 'https://everyayah.com/data/Alafasy_128kbps/047015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('47:16', 47, 16, 26, 508, 4561, 'وَمِنْهُمْ مَّنْ يَّسْتَمِعُ اِلَيْكَۚ حَتّٰىٓ اِذَا خَرَجُوْا مِنْ عِنْدِكَ قَالُوْا لِلَّذِيْنَ اُوْتُوا الْعِلْمَ مَاذَا قَالَ اٰنِفًا ۗ اُولٰۤىِٕكَ الَّذِيْنَ طَبَعَ اللّٰهُ عَلٰى قُلُوْبِهِمْ وَاتَّبَعُوْٓا اَهْوَاۤءَهُمْ', ' Di antara mereka (orang-orang kafir) ada orang (munafik) yang mendengarkan perkataanmu (Nabi Muhammad) sehingga apabila telah keluar dari sisimu, mereka berkata (untuk mengejek) kepada orang yang telah diberi ilmu (para sahabat Nabi), “Apa yang ia katakan tadi?” Mereka itu adalah orang-orang yang dikunci hatinya oleh Allah dan mengikuti hawa nafsunya.', '', 'https://everyayah.com/data/Alafasy_128kbps/047016.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('47:17', 47, 17, 26, 508, 4562, 'وَالَّذِيْنَ اهْتَدَوْا زَادَهُمْ هُدًى وَّاٰتٰىهُمْ تَقْوٰىهُمْ ', ' Orang-orang yang mendapat petunjuk akan ditambahi petunjuk(-nya) dan dianugerahi ketakwaan (oleh Allah).', '', 'https://everyayah.com/data/Alafasy_128kbps/047017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('47:18', 47, 18, 26, 508, 4563, 'فَهَلْ يَنْظُرُوْنَ اِلَّا السَّاعَةَ اَنْ تَأْتِيَهُمْ بَغْتَةً ۚ فَقَدْ جَاۤءَ اَشْرَاطُهَا ۚ فَاَنّٰى لَهُمْ اِذَا جَاۤءَتْهُمْ ذِكْرٰىهُمْ ', 'Apa lagi yang mereka (orang kafir) tunggu-tunggu selain hari Kiamat yang akan datang kepada mereka secara tiba-tiba karena tanda-tandanya sungguh telah datang? Maka, apa gunanya (kesadaran) mereka apabila (hari Kiamat) itu sudah datang?', '', 'https://everyayah.com/data/Alafasy_128kbps/047018.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('47:19', 47, 19, 26, 508, 4564, 'فَاعْلَمْ اَنَّهٗ لَآ اِلٰهَ اِلَّا اللّٰهُ وَاسْتَغْفِرْ لِذَنْۢبِكَ وَلِلْمُؤْمِنِيْنَ وَالْمُؤْمِنٰتِۚ وَاللّٰهُ يَعْلَمُ مُتَقَلَّبَكُمْ وَمَثْوٰىكُمْ ࣖ', 'Ketahuilah (Nabi Muhammad) bahwa tidak ada Tuhan (yang patut disembah) selain Allah serta mohonlah ampunan atas dosamu dan (dosa) orang-orang mukmin laki-laki dan perempuan. Allah mengetahui tempat kegiatan dan tempat istirahatmu.', '', 'https://everyayah.com/data/Alafasy_128kbps/047019.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('47:20', 47, 20, 26, 509, 4565, 'وَيَقُوْلُ الَّذِيْنَ اٰمَنُوْا لَوْلَا نُزِّلَتْ سُوْرَةٌ ۚفَاِذَآ اُنْزِلَتْ سُوْرَةٌ مُّحْكَمَةٌ وَّذُكِرَ فِيْهَا الْقِتَالُ ۙرَاَيْتَ الَّذِيْنَ فِيْ قُلُوْبِهِمْ مَّرَضٌ يَّنْظُرُوْنَ اِلَيْكَ نَظَرَ الْمَغْشِيِّ عَلَيْهِ مِنَ الْمَوْتِۗ فَاَوْلٰى لَهُمْۚ ', ' Orang-orang yang beriman berkata, “Mengapa tidak diturunkan suatu surah (tentang jihad)?” Maka, apabila diturunkan suatu surah yang jelas maksudnya dan di dalamnya disebutkan (perintah) perang, engkau melihat orang-orang yang di dalam hatinya ada penyakit (munafik) akan memandangmu seperti pandangan orang yang pingsan karena takut mati. Maka, itulah yang lebih pantas bagi mereka.', '', 'https://everyayah.com/data/Alafasy_128kbps/047020.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('47:21', 47, 21, 26, 509, 4566, 'طَاعَةٌ وَّقَوْلٌ مَّعْرُوْفٌۗ فَاِذَا عَزَمَ الْاَمْرُۗ فَلَوْ صَدَقُوا اللّٰهَ لَكَانَ خَيْرًا لَّهُمْۚ', ' (Seharusnya, mereka memilih) ketaatan (kepada Allah) dan tutur kata yang baik. Apabila perintah (perang) ditetapkan, (mereka tidak menyukainya). Padahal, jika mereka benar (beriman dan taat) kepada Allah, niscaya yang demikian itu lebih baik bagi mereka.', '', 'https://everyayah.com/data/Alafasy_128kbps/047021.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('47:22', 47, 22, 26, 509, 4567, 'فَهَلْ عَسَيْتُمْ اِنْ تَوَلَّيْتُمْ اَنْ تُفْسِدُوْا فِى الْاَرْضِ وَتُقَطِّعُوْٓا اَرْحَامَكُمْ ', ' Apakah seandainya berkuasa, kamu akan berbuat kerusakan di bumi dan memutuskan hubungan kekeluargaanmu?', '', 'https://everyayah.com/data/Alafasy_128kbps/047022.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('47:23', 47, 23, 26, 509, 4568, 'اُولٰۤىِٕكَ الَّذِيْنَ لَعَنَهُمُ اللّٰهُ فَاَصَمَّهُمْ وَاَعْمٰٓى اَبْصَارَهُمْ ', 'Mereka itulah orang-orang yang dilaknat oleh Allah. Lalu, Dia menulikan (pendengaran) dan membutakan penglihatan mereka.', '', 'https://everyayah.com/data/Alafasy_128kbps/047023.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('47:24', 47, 24, 26, 509, 4569, 'اَفَلَا يَتَدَبَّرُوْنَ الْقُرْاٰنَ اَمْ عَلٰى قُلُوْبٍ اَقْفَالُهَا ', 'Tidakkah mereka merenungkan Al-Qur’an ataukah hati mereka sudah terkunci?', '', 'https://everyayah.com/data/Alafasy_128kbps/047024.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('47:25', 47, 25, 26, 509, 4570, 'اِنَّ الَّذِيْنَ ارْتَدُّوْا عَلٰٓى اَدْبَارِهِمْ مِّنْۢ بَعْدِ مَا تَبَيَّنَ لَهُمُ الْهُدَى الشَّيْطٰنُ سَوَّلَ لَهُمْۗ وَاَمْلٰى لَهُمْ ', ' Sesungguhnya (bagi) orang-orang yang berbalik (pada kekufuran) setelah petunjuk itu jelas bagi mereka, setan menggoda mereka dan memanjangkan (angan-angan) mereka.', '', 'https://everyayah.com/data/Alafasy_128kbps/047025.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('47:26', 47, 26, 26, 509, 4571, 'ذٰلِكَ بِاَنَّهُمْ قَالُوْا لِلَّذِيْنَ كَرِهُوْا مَا نَزَّلَ اللّٰهُ سَنُطِيْعُكُمْ فِيْ بَعْضِ الْاَمْرِۚ وَاللّٰهُ يَعْلَمُ اِسْرَارَهُمْ ', ' Yang demikian itu (terjadi) karena sesungguhnya mereka (orang-orang munafik) telah mengatakan kepada orang-orang (Yahudi) yang tidak senang pada apa yang diturunkan Allah, “Kami akan mematuhimu dalam beberapa urusan.” Padahal, Allah mengetahui rahasia mereka.', '', 'https://everyayah.com/data/Alafasy_128kbps/047026.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('47:27', 47, 27, 26, 509, 4572, 'فَكَيْفَ اِذَا تَوَفَّتْهُمُ الْمَلٰۤىِٕكَةُ يَضْرِبُوْنَ وُجُوْهَهُمْ وَاَدْبَارَهُمْ ', 'Maka, bagaimana (nasib mereka) apabila malaikat (maut) mencabut nyawa mereka serta memukul wajah dan punggung mereka?', '', 'https://everyayah.com/data/Alafasy_128kbps/047027.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('47:28', 47, 28, 26, 509, 4573, 'ذٰلِكَ بِاَنَّهُمُ اتَّبَعُوْا مَآ اَسْخَطَ اللّٰهَ وَكَرِهُوْا رِضْوَانَهٗ فَاَحْبَطَ اَعْمَالَهُمْ ࣖ ', ' Yang demikian itu (terjadi) karena sesungguhnya mereka mengikuti apa yang menimbulkan kemurkaan Allah dan membenci (apa yang menimbulkan) keridaan-Nya. Oleh karena itu, Dia menghapus (pahala) amal-amal mereka.', '', 'https://everyayah.com/data/Alafasy_128kbps/047028.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('47:29', 47, 29, 26, 509, 4574, 'اَمْ حَسِبَ الَّذِيْنَ فِيْ قُلُوْبِهِمْ مَّرَضٌ اَنْ لَّنْ يُّخْرِجَ اللّٰهُ اَضْغَانَهُمْ ', ' Apakah orang-orang yang dalam hatinya ada penyakit mengira bahwa Allah tidak akan menampakkan kedengkian mereka (kepada Rasul dan kaum beriman)?', '', 'https://everyayah.com/data/Alafasy_128kbps/047029.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('47:30', 47, 30, 26, 510, 4575, 'وَلَوْ نَشَاۤءُ لَاَرَيْنٰكَهُمْ فَلَعَرَفْتَهُمْ بِسِيْمٰهُمْ ۗوَلَتَعْرِفَنَّهُمْ فِيْ لَحْنِ الْقَوْلِۗ وَاللّٰهُ يَعْلَمُ اَعْمَالَكُمْ ', ' Seandainya Kami berkehendak, niscaya Kami menunjukkan mereka kepadamu (Nabi Muhammad) sehingga engkau benar-benar dapat mengenali mereka melalui tanda-tandanya. Engkau pun benar-benar akan mengenali mereka melalui nada bicaranya. Allah mengetahui segala amal perbuatanmu.', '', 'https://everyayah.com/data/Alafasy_128kbps/047030.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('47:31', 47, 31, 26, 510, 4576, 'وَلَنَبْلُوَنَّكُمْ حَتّٰى نَعْلَمَ الْمُجٰهِدِيْنَ مِنْكُمْ وَالصّٰبِرِيْنَۙ وَنَبْلُوَا۟ اَخْبَارَكُمْ ', '. Sungguh, Kami benar-benar akan mengujimu sehingga mengetahui orang-orang yang berjihad dan bersabar di antara kamu serta menampakkan (kebenaran) berita-berita (tentang) kamu.', '', 'https://everyayah.com/data/Alafasy_128kbps/047031.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('47:32', 47, 32, 26, 510, 4577, 'اِنَّ الَّذِيْنَ كَفَرُوْا وَصَدُّوْا عَنْ سَبِيْلِ اللّٰهِ وَشَاۤقُّوا الرَّسُوْلَ مِنْۢ بَعْدِ مَا تَبَيَّنَ لَهُمُ الْهُدٰى لَنْ يَّضُرُّوا اللّٰهَ شَيْـًٔاۗ وَسَيُحْبِطُ اَعْمَالَهُمْ ', 'Sesungguhnya orang-orang yang kufur, menghalang-halangi (orang lain) dari jalan Allah, dan memusuhi Rasul setelah ada petunjuk yang jelas bagi mereka tidak akan dapat memberi mudarat (bahaya) kepada Allah sedikit pun. Dia (Allah) akan menghapus (pahala) amal-amal mereka.', '', 'https://everyayah.com/data/Alafasy_128kbps/047032.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('47:33', 47, 33, 26, 510, 4578, '۞ يٰٓاَيُّهَا الَّذِيْنَ اٰمَنُوْٓا اَطِيْعُوا اللّٰهَ وَاَطِيْعُوا الرَّسُوْلَ وَلَا تُبْطِلُوْٓا اَعْمَالَكُمْ', ' Wahai orang-orang yang beriman, taatilah Allah dan taatilah Rasul serta jangan batalkan amal-amalmu!', '', 'https://everyayah.com/data/Alafasy_128kbps/047033.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('47:34', 47, 34, 26, 510, 4579, 'اِنَّ الَّذِيْنَ كَفَرُوْا وَصَدُّوْا عَنْ سَبِيْلِ اللّٰهِ ثُمَّ مَاتُوْا وَهُمْ كُفَّارٌ فَلَنْ يَّغْفِرَ اللّٰهُ لَهُمْ ', ' Sesungguhnya orang-orang yang kufur dan menghalang-halangi (orang lain) dari jalan Allah, kemudian mereka mati dalam keadaan kafir, Allah tidak akan mengampuni mereka.', '', 'https://everyayah.com/data/Alafasy_128kbps/047034.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('47:35', 47, 35, 26, 510, 4580, 'فَلَا تَهِنُوْا وَتَدْعُوْٓا اِلَى السَّلْمِۖ وَاَنْتُمُ الْاَعْلَوْنَۗ وَاللّٰهُ مَعَكُمْ وَلَنْ يَّتِرَكُمْ اَعْمَالَكُمْ ', ' Maka, janganlah kamu lemah dan mengajak berdamai (saat bertemu dengan musuhmu), padahal kamulah yang paling unggul. Allah besertamu dan tidak akan mengurangi (pahala) amal-amalmu.', '', 'https://everyayah.com/data/Alafasy_128kbps/047035.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('47:36', 47, 36, 26, 510, 4581, 'اِنَّمَا الْحَيٰوةُ الدُّنْيَا لَعِبٌ وَّلَهْوٌ ۗوَاِنْ تُؤْمِنُوْا وَتَتَّقُوْا يُؤْتِكُمْ اُجُوْرَكُمْ وَلَا يَسْـَٔلْكُمْ اَمْوَالَكُمْ ', 'Sesungguhnya kehidupan dunia itu hanyalah permainan dan kelengahan. Jika kamu beriman dan bertakwa, Allah akan memberikan pahala kepadamu dan Dia tidak akan meminta harta-hartamu.', '', 'https://everyayah.com/data/Alafasy_128kbps/047036.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('47:37', 47, 37, 26, 510, 4582, 'اِنْ يَّسْـَٔلْكُمُوْهَا فَيُحْفِكُمْ تَبْخَلُوْا وَيُخْرِجْ اَضْغَانَكُمْ ', 'Jika Dia meminta harta kepadamu, lalu mendesakmu (agar memberikan semuanya), niscaya kamu akan kikir dan Dia akan menampakkan kedengkianmu.', '', 'https://everyayah.com/data/Alafasy_128kbps/047037.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('47:38', 47, 38, 26, 510, 4583, 'هٰٓاَنْتُمْ هٰٓؤُلَاۤءِ تُدْعَوْنَ لِتُنْفِقُوْا فِيْ سَبِيْلِ اللّٰهِۚ فَمِنْكُمْ مَّنْ يَّبْخَلُ ۚوَمَنْ يَّبْخَلْ فَاِنَّمَا يَبْخَلُ عَنْ نَّفْسِهٖ ۗوَاللّٰهُ الْغَنِيُّ وَاَنْتُمُ الْفُقَرَاۤءُ ۗوَاِنْ تَتَوَلَّوْا يَسْتَبْدِلْ قَوْمًا غَيْرَكُمْۙ ثُمَّ لَا يَكُوْنُوْٓا اَمْثَالَكُمْ ࣖ', ' Ingatlah bahwa kamu adalah orang-orang yang diajak untuk menginfakkan (hartamu) di jalan Allah. Lalu, di antara kamu ada orang yang kikir. Padahal, siapa yang kikir sesungguhnya dia kikir terhadap dirinya sendiri. Allahlah Yang Maha Kaya dan kamulah yang fakir. Jika kamu berpaling (dari jalan yang benar), Dia akan menggantikan (kamu) dengan kaum yang lain dan mereka tidak akan (durhaka) sepertimu.', '', 'https://everyayah.com/data/Alafasy_128kbps/047038.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('48:1', 48, 1, 26, 511, 4584, ' اِنَّا فَتَحْنَا لَكَ فَتْحًا مُّبِيْنًاۙ', 'Sesungguhnya Kami telah menganugerahkan kepadamu kemenangan yang nyata', '', 'https://everyayah.com/data/Alafasy_128kbps/048001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('48:2', 48, 2, 26, 511, 4585, 'لِّيَغْفِرَ لَكَ اللّٰهُ مَا تَقَدَّمَ مِنْ ذَنْۢبِكَ وَمَا تَاَخَّرَ وَيُتِمَّ نِعْمَتَهٗ عَلَيْكَ وَيَهْدِيَكَ صِرَاطًا مُّسْتَقِيْمًاۙ', 'agar Allah memberikan ampunan kepadamu (Nabi Muhammad) atas dosamu yang lalu dan yang akan datang, menyempurnakan nikmat-Nya atasmu, menunjukimu ke jalan yang lurus,', '', 'https://everyayah.com/data/Alafasy_128kbps/048002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('48:3', 48, 3, 26, 511, 4586, 'وَّيَنْصُرَكَ اللّٰهُ نَصْرًا عَزِيْزًا ', 'dan agar Allah menolongmu dengan pertolongan yang besar.', '', 'https://everyayah.com/data/Alafasy_128kbps/048003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('48:4', 48, 4, 26, 511, 4587, 'هُوَ الَّذِيْٓ اَنْزَلَ السَّكِيْنَةَ فِيْ قُلُوْبِ الْمُؤْمِنِيْنَ لِيَزْدَادُوْٓا اِيْمَانًا مَّعَ اِيْمَانِهِمْ ۗوَلِلّٰهِ جُنُوْدُ السَّمٰوٰتِ وَالْاَرْضِۗ وَكَانَ اللّٰهُ عَلِيْمًا حَكِيْمًاۙ', 'Dialah yang telah menurunkan ketenangan ke dalam hati orang-orang mukmin untuk menambah keimanan atas keimanan mereka (yang telah ada). Milik Allahlah bala tentara langit dan bumi dan Allah Maha Mengetahui lagi Maha Bijaksana.', '', 'https://everyayah.com/data/Alafasy_128kbps/048004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('48:5', 48, 5, 26, 511, 4588, 'لِّيُدْخِلَ الْمُؤْمِنِيْنَ وَالْمُؤْمِنٰتِ جَنّٰتٍ تَجْرِيْ مِنْ تَحْتِهَا الْاَنْهٰرُ خٰلِدِيْنَ فِيْهَا وَيُكَفِّرَ عَنْهُمْ سَيِّاٰتِهِمْۗ وَكَانَ ذٰلِكَ عِنْدَ اللّٰهِ فَوْزًا عَظِيْمًاۙ', '(Hal itu) agar Dia memasukkan orang-orang mukmin laki-laki dan perempuan ke dalam surga yang mengalir di bawahnya sungai-sungai. Mereka kekal di dalamnya. Dia pun akan menghapus kesalahan-kesalahan mereka. Yang demikian itu menurut Allah suatu keuntungan yang besar.', '', 'https://everyayah.com/data/Alafasy_128kbps/048005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('48:6', 48, 6, 26, 511, 4589, 'وَّيُعَذِّبَ الْمُنٰفِقِيْنَ وَالْمُنٰفِقٰتِ وَالْمُشْرِكِيْنَ وَالْمُشْرِكٰتِ الظَّاۤنِّيْنَ بِاللّٰهِ ظَنَّ السَّوْءِۗ عَلَيْهِمْ دَاۤىِٕرَةُ السَّوْءِۚ وَغَضِبَ اللّٰهُ عَلَيْهِمْ وَلَعَنَهُمْ وَاَعَدَّ لَهُمْ جَهَنَّمَۗ وَسَاۤءَتْ مَصِيْرًا ', '(Juga agar) Dia mengazab orang-orang munafik laki-laki dan perempuan serta orang-orang musyrik laki-laki dan perempuan yang berprasangka buruk terhadap Allah. Mereka akan mendapat giliran (azab) yang buruk. Allah pun murka kepada mereka, melaknat mereka, dan menyediakan (neraka) Jahanam bagi mereka. Itulah seburuk-buruk tempat kembali. ', '', 'https://everyayah.com/data/Alafasy_128kbps/048006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('48:7', 48, 7, 26, 511, 4590, 'وَلِلّٰهِ جُنُوْدُ السَّمٰوٰتِ وَالْاَرْضِۗ وَكَانَ اللّٰهُ عَزِيْزًا حَكِيْمًا', ' Milik Allahlah bala tentara langit dan bumi. Allah Maha Perkasa lagi Maha Bijaksana. ', '', 'https://everyayah.com/data/Alafasy_128kbps/048007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('48:8', 48, 8, 26, 511, 4591, 'اِنَّآ اَرْسَلْنٰكَ شَاهِدًا وَّمُبَشِّرًا وَّنَذِيْرًاۙ', ' Sesungguhnya Kami mengutus engkau (Nabi Muhammad) sebagai saksi, pembawa berita gembira, dan pemberi peringatan', '', 'https://everyayah.com/data/Alafasy_128kbps/048008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('48:9', 48, 9, 26, 511, 4592, 'لِّتُؤْمِنُوْا بِاللّٰهِ وَرَسُوْلِهٖ وَتُعَزِّرُوْهُ وَتُوَقِّرُوْهُۗ وَتُسَبِّحُوْهُ بُكْرَةً وَّاَصِيْلًا ', ' agar kamu sekalian beriman kepada Allah dan Rasul-Nya, menguatkan (agama)-Nya, membesarkan-Nya, dan bertasbih kepada-Nya, baik pagi maupun petang.', '', 'https://everyayah.com/data/Alafasy_128kbps/048009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('48:10', 48, 10, 26, 512, 4593, 'اِنَّ الَّذِيْنَ يُبَايِعُوْنَكَ اِنَّمَا يُبَايِعُوْنَ اللّٰهَ ۗيَدُ اللّٰهِ فَوْقَ اَيْدِيْهِمْ ۚ فَمَنْ نَّكَثَ فَاِنَّمَا يَنْكُثُ عَلٰى نَفْسِهٖۚ وَمَنْ اَوْفٰى بِمَا عٰهَدَ عَلَيْهُ اللّٰهَ فَسَيُؤْتِيْهِ اَجْرًا عَظِيْمًا ࣖ ', 'Sesungguhnya orang-orang yang berjanji setia kepadamu (Nabi Muhammad), (pada hakikatnya) mereka berjanji setia kepada Allah. Tangan692) Allah di atas tangan mereka. Oleh sebab itu, siapa yang melanggar janji (setia itu), maka sesungguhnya (akibat buruk dari) pelanggaran itu hanya akan menimpa dirinya sendiri. Siapa yang menepati janjinya kepada Allah, maka Dia akan menganugerahinya pahala yang besar. ', '692) Ini termasuk ayat-ayat sifat. Ahli tafsir berbeda pendapat mengenai ayat ini. Sebagian menjelaskan bahwa yang dimaksud tangan adalah kekuatan dan kekuasaan Allah. Sebagian yang lain memahaminya sebagai pengawasan Allah akan janji setia yang diberikan oleh beberapa orang kepada Nabi Muhammad saw.', 'https://everyayah.com/data/Alafasy_128kbps/048010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('48:11', 48, 11, 26, 512, 4594, 'سَيَقُوْلُ لَكَ الْمُخَلَّفُوْنَ مِنَ الْاَعْرَابِ شَغَلَتْنَآ اَمْوَالُنَا وَاَهْلُوْنَا فَاسْتَغْفِرْ لَنَا ۚيَقُوْلُوْنَ بِاَلْسِنَتِهِمْ مَّا لَيْسَ فِيْ قُلُوْبِهِمْۗ قُلْ فَمَنْ يَّمْلِكُ لَكُمْ مِّنَ اللّٰهِ شَيْـًٔا اِنْ اَرَادَ بِكُمْ ضَرًّا اَوْ اَرَادَ بِكُمْ نَفْعًا ۗبَلْ كَانَ اللّٰهُ بِمَا تَعْمَلُوْنَ خَبِيْرًا ', ' Orang-orang Arab Badui yang ditinggalkan (karena tidak mau ikut ke Hudaibiah) akan berkata kepadamu, “Kami telah disibukkan oleh harta dan keluarga kami, maka mohonkanlah ampunan untuk kami.” Mereka mengucapkan dengan mulutnya apa yang tidak ada dalam hatinya. Katakanlah, “Siapakah yang dapat menghalang-halangi kehendak Allah jika Dia menghendaki mudarat terhadap kamu atau jika Dia menghendaki manfaat bagimu? Bahkan, Allah Maha Teliti terhadap apa yang kamu kerjakan.” ', '', 'https://everyayah.com/data/Alafasy_128kbps/048011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('48:12', 48, 12, 26, 512, 4595, 'بَلْ ظَنَنْتُمْ اَنْ لَّنْ يَّنْقَلِبَ الرَّسُوْلُ وَالْمُؤْمِنُوْنَ اِلٰٓى اَهْلِيْهِمْ اَبَدًا وَّزُيِّنَ ذٰلِكَ فِيْ قُلُوْبِكُمْ وَظَنَنْتُمْ ظَنَّ السَّوْءِۚ وَكُنْتُمْ قَوْمًاۢ  بُوْرًا ', 'Bahkan, (semula) kamu menyangka bahwa Rasul dan orang-orang mukmin sama sekali tidak akan kembali lagi kepada keluarga mereka selama-lamanya dan dijadikan terasa indah yang demikian itu di dalam hatimu. Kamu telah berprasangka buruk. Oleh sebab itu, kamu menjadi kaum yang binasa.', '', 'https://everyayah.com/data/Alafasy_128kbps/048012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('48:13', 48, 13, 26, 512, 4596, 'وَمَنْ لَّمْ يُؤْمِنْۢ بِاللّٰهِ وَرَسُوْلِهٖ فَاِنَّآ اَعْتَدْنَا لِلْكٰفِرِيْنَ سَعِيْرًا ', ' Siapa yang tidak beriman kepada Allah dan Rasul-Nya, sesungguhnya Kami telah menyediakan untuk orang-orang kafir itu (neraka) Sa‘ir (yang menyala-nyala).', '', 'https://everyayah.com/data/Alafasy_128kbps/048013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('48:14', 48, 14, 26, 512, 4597, 'وَلِلّٰهِ مُلْكُ السَّمٰوٰتِ وَالْاَرْضِۗ يَغْفِرُ لِمَنْ يَّشَاۤءُ وَيُعَذِّبُ مَنْ يَّشَاۤءُ ۗوَكَانَ اللّٰهُ غَفُوْرًا رَّحِيْمًا', ' Milik Allahlah kerajaan langit dan bumi. Dia mengampuni siapa yang Dia kehendaki dan mengazab siapa yang Dia kehendaki. Allah Maha Pengampun lagi Maha Penyayang.', '', 'https://everyayah.com/data/Alafasy_128kbps/048014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('48:15', 48, 15, 26, 512, 4598, 'سَيَقُوْلُ الْمُخَلَّفُوْنَ اِذَا انْطَلَقْتُمْ اِلٰى مَغَانِمَ لِتَأْخُذُوْهَا ذَرُوْنَا نَتَّبِعْكُمْ ۚ يُرِيْدُوْنَ اَنْ يُّبَدِّلُوْا كَلٰمَ اللّٰهِ ۗ قُلْ لَّنْ تَتَّبِعُوْنَا كَذٰلِكُمْ قَالَ اللّٰهُ مِنْ قَبْلُ  ۖفَسَيَقُوْلُوْنَ بَلْ تَحْسُدُوْنَنَا ۗ بَلْ كَانُوْا لَا يَفْقَهُوْنَ اِلَّا قَلِيْلًا', 'Apabila kamu nanti berangkat untuk mengambil rampasan perang, orang-orang Badui yang ditinggalkan itu akan berkata, “Biarkanlah kami mengikutimu.” Mereka hendak mengubah janji Allah.693)  Katakanlah, “Kamu sekali-kali  tidak (boleh) mengikuti kami. Demikianlah yang telah difirmankan Allah sebelumnya.” Maka, mereka akan berkata, “Sebenarnya kamu dengki kepada kami,” padahal mereka tidak mengerti kecuali sedikit sekali.', '693) Mereka ingin mengubah janji Allah bahwa rampasan itu (Khaibar) hanya untuk orang-orang yang ikut dalam Perjanjian Hudaibiah. Perjanjian itu terjadi pada akhir tahun keenam Hijriah.Kemudian, pada Muharam tahun ketujuh, Rasulullah dan para sahabat berangkat perang menuju Khaibar. Pada perang Khaibar ini, orang-orang Badui yang tidak ikut dalam Perjanjian Hudaibiah bermaksud untuk ikut berangkat ke Khaibar agar turut serta mendapatkan rampasan perang. Allah mengabarkan bahwa Dia telah berjanji bahwa rampasan perang ini hanya untuk mereka yang ikut dalam Perjanjian Hudaibiah.', 'https://everyayah.com/data/Alafasy_128kbps/048015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('48:16', 48, 16, 26, 513, 4599, 'قُلْ لِّلْمُخَلَّفِيْنَ مِنَ الْاَعْرَابِ سَتُدْعَوْنَ اِلٰى قَوْمٍ اُولِيْ بَأْسٍ شَدِيْدٍ تُقَاتِلُوْنَهُمْ اَوْ يُسْلِمُوْنَ ۚ فَاِنْ تُطِيْعُوْا يُؤْتِكُمُ اللّٰهُ اَجْرًا حَسَنًا ۚ وَاِنْ تَتَوَلَّوْا كَمَا تَوَلَّيْتُمْ مِّنْ قَبْلُ يُعَذِّبْكُمْ عَذَابًا اَلِيْمًا ', ' Katakanlah kepada orang-orang Arab Badui yang ditinggalkan itu, “Kamu akan diajak untuk (memerangi) kaum yang mempunyai kekuatan yang besar. Kamu akan memerangi mereka atau mereka menyerah. Jika kamu mematuhi (ajakan itu), Allah akan memberimu balasan yang baik. Akan tetapi, jika kamu berpaling seperti yang kamu perbuat sebelumnya, Dia akan mengazabmu dengan azab yang pedih.”', '', 'https://everyayah.com/data/Alafasy_128kbps/048016.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('48:17', 48, 17, 26, 513, 4600, 'لَيْسَ عَلَى الْاَعْمٰى حَرَجٌ وَّلَا عَلَى الْاَعْرَجِ حَرَجٌ وَّلَا عَلَى الْمَرِيْضِ حَرَجٌ ۗ وَمَنْ يُّطِعِ اللّٰهَ وَرَسُوْلَهٗ يُدْخِلْهُ جَنّٰتٍ تَجْرِيْ مِنْ تَحْتِهَا الْاَنْهٰرُ ۚ وَمَنْ يَّتَوَلَّ يُعَذِّبْهُ عَذَابًا اَلِيْمًا ࣖ ', ' Tidak ada dosa atas orang-orang yang buta, orang-orang yang pincang, dan orang-orang yang sakit (apabila tidak ikut berperang). Siapa yang taat kepada Allah dan Rasul-Nya, dia akan dimasukkan oleh-Nya ke dalam surga yang mengalir bawahnya sungai-sungai. Akan tetapi, siapa yang berpaling, dia akan diazab oleh-Nya dengan azab yang pedih. ', '', 'https://everyayah.com/data/Alafasy_128kbps/048017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('48:18', 48, 18, 26, 513, 4601, '۞ لَقَدْ رَضِيَ اللّٰهُ عَنِ الْمُؤْمِنِيْنَ اِذْ يُبَايِعُوْنَكَ تَحْتَ الشَّجَرَةِ فَعَلِمَ مَا فِيْ قُلُوْبِهِمْ فَاَنْزَلَ السَّكِيْنَةَ عَلَيْهِمْ وَاَثَابَهُمْ فَتْحًا قَرِيْبًاۙ', ' Sungguh, Allah benar-benar telah meridai orang-orang mukmin ketika mereka berjanji setia kepadamu (Nabi Muhammad) di bawah sebuah pohon. Dia mengetahui apa yang ada dalam hati mereka, lalu Dia menganugerahkan ketenangan kepada mereka dan memberi balasan berupa kemenangan yang dekat', '', 'https://everyayah.com/data/Alafasy_128kbps/048018.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('48:19', 48, 19, 26, 513, 4602, 'وَّمَغَانِمَ كَثِيْرَةً يَّأْخُذُوْنَهَا ۗ وَكَانَ اللّٰهُ عَزِيْزًا حَكِيْمًا ', ' dan harta rampasan perang yang banyak yang dapat mereka ambil. Allah Maha Perkasa lagi Maha Bijaksana.', '', 'https://everyayah.com/data/Alafasy_128kbps/048019.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('48:20', 48, 20, 26, 513, 4603, 'وَعَدَكُمُ اللّٰهُ مَغَانِمَ كَثِيْرَةً تَأْخُذُوْنَهَا فَعَجَّلَ لَكُمْ هٰذِهٖ وَكَفَّ اَيْدِيَ النَّاسِ عَنْكُمْۚ وَلِتَكُوْنَ اٰيَةً لِّلْمُؤْمِنِيْنَ وَيَهْدِيَكُمْ صِرَاطًا مُّسْتَقِيْمًاۙ', 'Allah telah menjanjikan kepadamu rampasan perang yang banyak yang (nanti) dapat kamu ambil, maka Dia menyegerakan (harta rampasan perang) ini untukmu.[694) Dia menahan tangan (mencegah) manusia dari (upaya menganiaya)-mu (agar kamu mensyukuri-Nya), agar menjadi bukti bagi orang-orang mukmin, dan agar Dia menunjukkan kamu ke jalan yang lurus. ', '694) Allah menjanjikan harta rampasan perang yang banyak kepada kaum muslim. Sebagai pendahuluan, Allah memberikannya pada Perang Khaibar.', 'https://everyayah.com/data/Alafasy_128kbps/048020.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('48:21', 48, 21, 26, 513, 4604, 'وَّاُخْرٰى لَمْ تَقْدِرُوْا عَلَيْهَا قَدْ اَحَاطَ اللّٰهُ بِهَا ۗوَكَانَ اللّٰهُ عَلٰى كُلِّ شَيْءٍ قَدِيْرًا ', ' (Allah menjanjikan pula rampasan perang) lain yang kamu belum dapat menguasainya, tetapi sungguh Allah telah menguasainya. Allah Maha Kuasa atas segala sesuatu.', '', 'https://everyayah.com/data/Alafasy_128kbps/048021.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('48:22', 48, 22, 26, 513, 4605, 'وَلَوْ قَاتَلَكُمُ الَّذِيْنَ كَفَرُوْا لَوَلَّوُا الْاَدْبَارَ ثُمَّ لَا يَجِدُوْنَ وَلِيًّا وَّلَا نَصِيْرًا ', ' Sekiranya orang-orang yang kufur itu memerangi kamu, pastilah mereka akan berbalik melarikan diri (kalah), kemudian mereka tidak akan mendapatkan pelindung dan penolong. ', '', 'https://everyayah.com/data/Alafasy_128kbps/048022.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('48:23', 48, 23, 26, 513, 4606, 'سُنَّةَ اللّٰهِ الَّتِيْ قَدْ خَلَتْ مِنْ قَبْلُ  ۖوَلَنْ تَجِدَ لِسُنَّةِ اللّٰهِ تَبْدِيْلًا ', ' (Demikianlah) sunatullah yang sungguh telah berlaku sejak dahulu. Kamu sekali-kali tidak akan menemukan perubahan pada sunatullah itu.', '', 'https://everyayah.com/data/Alafasy_128kbps/048023.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('48:24', 48, 24, 26, 514, 4607, 'وَهُوَ الَّذِيْ كَفَّ اَيْدِيَهُمْ عَنْكُمْ وَاَيْدِيَكُمْ عَنْهُمْ بِبَطْنِ مَكَّةَ مِنْۢ بَعْدِ اَنْ اَظْفَرَكُمْ عَلَيْهِمْ ۗوَكَانَ اللّٰهُ بِمَا تَعْمَلُوْنَ بَصِيْرًا ', ' Dialah (Allah) yang menahan tangan (mencegah) mereka dari (upaya menganiaya) kamu dan menahan tangan (mencegah) kamu dari (upaya menganiaya) mereka di tengah (kota) Makkah setelah Dia memenangkan kamu atas mereka. Allah Maha Melihat apa yang kamu kerjakan. ', '', 'https://everyayah.com/data/Alafasy_128kbps/048024.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('48:25', 48, 25, 26, 514, 4608, 'هُمُ الَّذِيْنَ كَفَرُوْا وَصَدُّوْكُمْ عَنِ الْمَسْجِدِ الْحَرَامِ وَالْهَدْيَ مَعْكُوْفًا اَنْ يَّبْلُغَ مَحِلَّهٗ ۚوَلَوْلَا رِجَالٌ مُّؤْمِنُوْنَ وَنِسَاۤءٌ مُّؤْمِنٰتٌ لَّمْ تَعْلَمُوْهُمْ اَنْ تَطَـُٔوْهُمْ فَتُصِيْبَكُمْ مِّنْهُمْ مَّعَرَّةٌ ۢبِغَيْرِ عِلْمٍ ۚ لِيُدْخِلَ اللّٰهُ فِيْ رَحْمَتِهٖ مَنْ يَّشَاۤءُۚ  لَوْ تَزَيَّلُوْا لَعَذَّبْنَا الَّذِيْنَ كَفَرُوْا مِنْهُمْ عَذَابًا اَلِيْمًا', ' Merekalah orang-orang yang kufur dan menghalang-halangi kamu (masuk) Masjidilharam dan (menghalangi pula) hewan-hewan kurban yang terkumpul sampai ke tempat (penyembelihan)-nya. Seandainya tidak ada beberapa orang laki-laki dan perempuan yang beriman yang tidak kamu ketahui (keberadaannya karena berbaur dengan orang-orang kafir, yaitu seandainya tidak dikhawatirkan) kamu akan membunuh mereka yang menyebabkan kamu ditimpa kesulitan tanpa kamu sadari, (maka Allah tidak akan mencegahmu untuk memerangi mereka. Itu semua) karena Allah hendak memasukkan siapa yang Dia kehendaki ke dalam rahmat-Nya. Sekiranya mereka terpisah, tentu Kami akan mengazab orang-orang yang kufur di antara mereka dengan azab yang pedih.', '', 'https://everyayah.com/data/Alafasy_128kbps/048025.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('48:26', 48, 26, 26, 514, 4609, 'اِذْ جَعَلَ الَّذِيْنَ كَفَرُوْا فِيْ قُلُوْبِهِمُ الْحَمِيَّةَ حَمِيَّةَ الْجَاهِلِيَّةِ فَاَنْزَلَ اللّٰهُ سَكِيْنَتَهٗ عَلٰى رَسُوْلِهٖ وَعَلَى الْمُؤْمِنِيْنَ وَاَلْزَمَهُمْ كَلِمَةَ التَّقْوٰى وَكَانُوْٓا اَحَقَّ بِهَا وَاَهْلَهَا ۗوَكَانَ اللّٰهُ بِكُلِّ شَيْءٍ عَلِيْمًا ࣖ ', '(Kami akan mengazab) orang-orang yang kufur ketika mereka menanamkan kesombongan dalam hati mereka, (yaitu) kesombongan jahiliah, lalu Allah menurunkan ketenangan kepada Rasul-Nya dan orang-orang mukmin. (Allah) menetapkan pula untuk mereka kalimat takwa.695) Mereka lebih berhak atas kalimat itu dan patut memilikinya. Allah Maha Mengetahui segala sesuatu.', '695)Kalimat takwa adalah kalimat tauhid.', 'https://everyayah.com/data/Alafasy_128kbps/048026.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('48:27', 48, 27, 26, 514, 4610, 'لَقَدْ صَدَقَ اللّٰهُ رَسُوْلَهُ الرُّءْيَا بِالْحَقِّ ۚ لَتَدْخُلُنَّ الْمَسْجِدَ الْحَرَامَ اِنْ شَاۤءَ اللّٰهُ اٰمِنِيْنَۙ مُحَلِّقِيْنَ رُءُوْسَكُمْ وَمُقَصِّرِيْنَۙ  لَا تَخَافُوْنَ ۗفَعَلِمَ مَا لَمْ تَعْلَمُوْا فَجَعَلَ مِنْ دُوْنِ ذٰلِكَ فَتْحًا قَرِيْبًا ', 'Sungguh, Allah benar-benar akan membuktikan kepada Rasul-Nya tentang kebenaran mimpinya dengan sebenar-benarnya, (yaitu) bahwa kamu pasti akan memasuki Masjidilharam, jika Allah menghendaki, dalam keadaan aman, dengan mencukur rambut kepala,696) dan memendekkannya, sedang kamu tidak merasa takut. Allah mengetahui apa yang tidak kamu ketahui dan sebelum itu Dia telah memberikan kemenangan yang dekat.697)', '696) Yang dimaksud dengan mencukur rambut kepala adalah tahalul setelah umrah.
 697)Selang beberapa lama sebelum terjadi Perjanjian Hudaibiah, Nabi Muhammad saw. bermimpi bahwa beliau bersama para sahabatnya memasuki kota Makkah dan Masjidilharam.Sebagian mereka menggunduli rambut dan yang lain memendekkannya. Nabi mengatakan bahwa mimpi beliau itu akan terjadi. Kemudian, berita ini tersiar di kalangan kaum muslim, orang-orang munafik, serta orang-orang Yahudi dan Nasrani. Setelah Perjanjian Hudaibiahtercapai dan kaum muslim gagal memasuki Makkah, orang-orang munafik memperolok-olokkan Nabi dan menyatakan bahwa mimpi beliau adalah bohong belaka. Maka, turunlah ayat ini yang menyatakan bahwa mimpi Nabi itu pasti akan menjadi kenyataan pada tahun yang akan datang. Sekiranya pada tahun terjadinya Perjanjian Hudaibiah itu kaum muslim memasuki kota Makkah, dikhawatirkan jiwa orang-orang Makkah yang menyembunyikan imannya akan terancam.', 'https://everyayah.com/data/Alafasy_128kbps/048027.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('48:28', 48, 28, 26, 514, 4611, 'هُوَ الَّذِيْٓ اَرْسَلَ رَسُوْلَهٗ بِالْهُدٰى وَدِيْنِ الْحَقِّ لِيُظْهِرَهٗ عَلَى الدِّيْنِ كُلِّهٖ ۗوَكَفٰى بِاللّٰهِ شَهِيْدًا ', 'Dialah yang mengutus Rasul-Nya dengan membawa petunjuk dan agama yang benar agar Dia mengunggulkan (agama tersebut) atas semua agama. Cukuplah Allah sebagai saksi.', '', 'https://everyayah.com/data/Alafasy_128kbps/048028.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('48:29', 48, 29, 26, 515, 4612, 'مُحَمَّدٌ رَّسُوْلُ اللّٰهِ ۗوَالَّذِيْنَ مَعَهٗٓ اَشِدَّاۤءُ عَلَى الْكُفَّارِ رُحَمَاۤءُ بَيْنَهُمْ تَرٰىهُمْ رُكَّعًا سُجَّدًا يَّبْتَغُوْنَ فَضْلًا مِّنَ اللّٰهِ وَرِضْوَانًا ۖ سِيْمَاهُمْ فِيْ وُجُوْهِهِمْ مِّنْ اَثَرِ السُّجُوْدِ ۗذٰلِكَ مَثَلُهُمْ فِى التَّوْرٰىةِ  ۖوَمَثَلُهُمْ فِى الْاِنْجِيْلِۚ  كَزَرْعٍ اَخْرَجَ شَطْـَٔهٗ فَاٰزَرَهٗ فَاسْتَغْلَظَ فَاسْتَوٰى عَلٰى سُوْقِهٖ يُعْجِبُ الزُّرَّاعَ لِيَغِيْظَ بِهِمُ الْكُفَّارَ ۗوَعَدَ اللّٰهُ الَّذِيْنَ اٰمَنُوْا وَعَمِلُوا الصّٰلِحٰتِ مِنْهُمْ مَّغْفِرَةً وَّاَجْرًا عَظِيْمًا ࣖ ', ' Nabi Muhammad adalah utusan Allah dan orang-orang yang bersama dengannya bersikap keras terhadap orang-orang kafir (yang bersikap memusuhi), tetapi berkasih sayang sesama mereka. Kamu melihat mereka rukuk dan sujud mencari karunia Allah dan keridaan-Nya. Pada wajah mereka tampak tanda-tanda bekas sujud (bercahaya). Itu adalah sifat-sifat mereka (yang diungkapkan) dalam Taurat dan Injil, yaitu seperti benih yang mengeluarkan tunasnya, kemudian tunas itu makin kuat, lalu menjadi besar dan tumbuh di atas batangnya. Tanaman itu menyenangkan hati orang yang menanamnya. (Keadaan mereka diumpamakan seperti itu) karena Allah hendak membuat marah orang-orang kafir. Allah menjanjikan kepada orang-orang yang beriman dan mengerjakan kebajikan di antara mereka ampunan dan pahala yang besar. ', '', 'https://everyayah.com/data/Alafasy_128kbps/048029.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('49:1', 49, 1, 26, 515, 4613, 'يٰٓاَيُّهَا الَّذِيْنَ اٰمَنُوْا لَا تُقَدِّمُوْا بَيْنَ يَدَيِ اللّٰهِ وَرَسُوْلِهٖ وَاتَّقُوا اللّٰهَ ۗاِنَّ اللّٰهَ سَمِيْعٌ عَلِيْمٌ ', ' Wahai orang-orang yang beriman, janganlah mendahului Allah dan Rasul-Nya698) dan bertakwalah kepada Allah. Sesungguhnya Allah Maha Mendengar lagi Maha Mengetahui.', '698)Maksudnya adalah bahwa orang-orang mukmin tidak boleh menetapkan suatu hukum sebelum ada ketetapan dari Allah dan Rasul-Nya dalam hal yang dimungkinkan adanya penjelasan dari Allah atau Rasul-Nya.', 'https://everyayah.com/data/Alafasy_128kbps/049001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('49:2', 49, 2, 26, 515, 4614, 'يٰٓاَيُّهَا الَّذِيْنَ اٰمَنُوْا لَا تَرْفَعُوْٓا اَصْوَاتَكُمْ فَوْقَ صَوْتِ النَّبِيِّ وَلَا تَجْهَرُوْا لَهٗ بِالْقَوْلِ كَجَهْرِ بَعْضِكُمْ لِبَعْضٍ اَنْ تَحْبَطَ اَعْمَالُكُمْ وَاَنْتُمْ لَا تَشْعُرُوْنَ ', ' Wahai orang-orang yang beriman, janganlah meninggikan suaramu melebihi suara Nabi dan janganlah berkata kepadanya dengan suara keras sebagaimana kerasnya (suara) sebagian kamu terhadap yang lain. Hal itu dikhawatirkan akan membuat (pahala) segala amalmu terhapus, sedangkan kamu tidak menyadarinya.', '', 'https://everyayah.com/data/Alafasy_128kbps/049002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('49:3', 49, 3, 26, 515, 4615, 'اِنَّ الَّذِيْنَ يَغُضُّوْنَ اَصْوَاتَهُمْ عِنْدَ رَسُوْلِ اللّٰهِ اُولٰۤىِٕكَ الَّذِيْنَ امْتَحَنَ اللّٰهُ قُلُوْبَهُمْ لِلتَّقْوٰىۗ  لَهُمْ مَّغْفِرَةٌ وَّاَجْرٌ عَظِيْمٌ ', ' Sesungguhnya orang-orang yang merendahkan suaranya di sisi Rasulullah, mereka itulah orang-orang yang telah diuji hatinya oleh Allah untuk bertakwa. Mereka akan memperoleh ampunan dan pahala yang besar.', '', 'https://everyayah.com/data/Alafasy_128kbps/049003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('49:4', 49, 4, 26, 515, 4616, 'اِنَّ الَّذِيْنَ يُنَادُوْنَكَ مِنْ وَّرَاۤءِ الْحُجُرٰتِ اَكْثَرُهُمْ لَا يَعْقِلُوْنَ ', 'Sesungguhnya orang-orang yang memanggil engkau (Nabi Muhammad) dari luar kamar(-mu), kebanyakan mereka tidak mengerti.', '', 'https://everyayah.com/data/Alafasy_128kbps/049004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('49:5', 49, 5, 26, 516, 4617, 'وَلَوْ اَنَّهُمْ صَبَرُوْا حَتّٰى تَخْرُجَ اِلَيْهِمْ لَكَانَ خَيْرًا لَّهُمْ ۗوَاللّٰهُ غَفُوْرٌ رَّحِيْمٌ', 'Seandainya mereka bersabar sampai engkau keluar menemui mereka, tentu akan lebih baik bagi mereka. Allah Maha Pengampun lagi Maha Penyayang. ', '', 'https://everyayah.com/data/Alafasy_128kbps/049005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('49:6', 49, 6, 26, 516, 4618, 'يٰٓاَيُّهَا الَّذِيْنَ اٰمَنُوْٓا اِنْ جَاۤءَكُمْ فَاسِقٌۢ بِنَبَاٍ فَتَبَيَّنُوْٓا اَنْ تُصِيْبُوْا قَوْمًاۢ بِجَهَالَةٍ فَتُصْبِحُوْا عَلٰى مَا فَعَلْتُمْ نٰدِمِيْنَ ', 'Wahai orang-orang yang beriman, jika seorang fasik datang kepadamu membawa berita penting, maka telitilah kebenarannya agar kamu tidak mencelakakan suatu kaum karena ketidaktahuan(-mu) yang berakibat kamu menyesali perbuatanmu itu. ', '', 'https://everyayah.com/data/Alafasy_128kbps/049006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('49:7', 49, 7, 26, 516, 4619, 'وَاعْلَمُوْٓا اَنَّ فِيْكُمْ رَسُوْلَ اللّٰهِ ۗ لَوْ يُطِيْعُكُمْ فِيْ كَثِيْرٍ مِّنَ الْاَمْرِ لَعَنِتُّمْ وَلٰكِنَّ اللّٰهَ حَبَّبَ اِلَيْكُمُ الْاِيْمَانَ وَزَيَّنَهٗ فِيْ قُلُوْبِكُمْ وَكَرَّهَ اِلَيْكُمُ الْكُفْرَ وَالْفُسُوْقَ وَالْعِصْيَانَ ۗ اُولٰۤىِٕكَ هُمُ الرّٰشِدُوْنَۙ', ' Ketahuilah bahwa di tengah-tengah kamu ada Rasulullah. Seandainya dia menuruti (kemauan)-mu dalam banyak hal, pasti kamu akan mendapatkan kesusahan. Akan tetapi, 
Allah menjadikanmu cinta pada keimanan dan menjadikan (iman) itu indah dalam hatimu serta menjadikanmu benci pada kekufuran, kefasikan, dan kemaksiatan. Mereka itulah orang-orang yang mengikuti jalan kebenaran.
', '', 'https://everyayah.com/data/Alafasy_128kbps/049007.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('49:8', 49, 8, 26, 516, 4620, 'فَضْلًا مِّنَ اللّٰهِ وَنِعْمَةً ۗوَاللّٰهُ عَلِيْمٌ حَكِيْمٌ ', ' (Itu) sebagai karunia dan nikmat dari Allah. Allah Maha Mengetahui lagi Maha Bijaksana', '', 'https://everyayah.com/data/Alafasy_128kbps/049008.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('49:9', 49, 9, 26, 516, 4621, 'وَاِنْ طَاۤىِٕفَتٰنِ مِنَ الْمُؤْمِنِيْنَ اقْتَتَلُوْا فَاَصْلِحُوْا بَيْنَهُمَاۚ فَاِنْۢ بَغَتْ اِحْدٰىهُمَا عَلَى الْاُخْرٰى فَقَاتِلُوا الَّتِيْ تَبْغِيْ حَتّٰى تَفِيْۤءَ اِلٰٓى اَمْرِ اللّٰهِ ۖفَاِنْ فَاۤءَتْ فَاَصْلِحُوْا بَيْنَهُمَا بِالْعَدْلِ وَاَقْسِطُوْا ۗاِنَّ اللّٰهَ يُحِبُّ الْمُقْسِطِيْنَ ', 'Jika ada dua golongan orang-orang mukmin bertikai, damaikanlah keduanya. Jika salah satu dari keduanya berbuat aniaya terhadap (golongan) yang lain, perangilah (golongan) yang berbuat aniaya itu, sehingga golongan itu kembali kepada perintah Allah. Jika golongan itu telah kembali (kepada perintah Allah), damaikanlah keduanya dengan adil. Bersikaplah adil! Sesungguhnya Allah mencintai orang-orang yang bersikap adil.', '', 'https://everyayah.com/data/Alafasy_128kbps/049009.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('49:10', 49, 10, 26, 516, 4622, 'اِنَّمَا الْمُؤْمِنُوْنَ اِخْوَةٌ فَاَصْلِحُوْا بَيْنَ اَخَوَيْكُمْ  وَاتَّقُوا اللّٰهَ لَعَلَّكُمْ تُرْحَمُوْنَ ࣖ ', ' Sesungguhnya orang-orang mukmin itu bersaudara, karena itu damaikanlah kedua saudaramu (yang bertikai) dan bertakwalah kepada Allah agar kamu dirahmati. ', '', 'https://everyayah.com/data/Alafasy_128kbps/049010.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('49:11', 49, 11, 26, 516, 4623, 'يٰٓاَيُّهَا الَّذِيْنَ اٰمَنُوْا لَا يَسْخَرْ قَوْمٌ مِّنْ قَوْمٍ عَسٰٓى اَنْ يَّكُوْنُوْا خَيْرًا مِّنْهُمْ وَلَا نِسَاۤءٌ مِّنْ نِّسَاۤءٍ عَسٰٓى اَنْ يَّكُنَّ خَيْرًا مِّنْهُنَّۚ وَلَا تَلْمِزُوْٓا اَنْفُسَكُمْ وَلَا تَنَابَزُوْا بِالْاَلْقَابِۗ بِئْسَ الِاسْمُ الْفُسُوْقُ بَعْدَ الْاِيْمَانِۚ وَمَنْ لَّمْ يَتُبْ فَاُولٰۤىِٕكَ هُمُ الظّٰلِمُوْنَ ', 'Wahai orang-orang yang beriman, janganlah suatu kaum mengolok-olok kaum yang lain (karena) boleh jadi mereka (yang diolok-olokkan itu) lebih baik daripada mereka (yang mengolok-olok) dan jangan pula perempuan-perempuan (mengolok-olok) perempuan lain (karena) boleh jadi perempuan (yang diolok-olok itu) lebih baik daripada perempuan (yang mengolok-olok). Janganlah kamu saling mencela dan saling memanggil dengan julukan yang buruk. Seburuk-buruk panggilan adalah (panggilan) fasik699) setelah beriman. Siapa yang tidak bertobat, mereka itulah orang-orang zalim. ', '699)Panggilan fasik adalah panggilan dengan menggunakan kata-kata yang mengandung penghinaan atau tidak mencerminkan sifat seorang mukmin.', 'https://everyayah.com/data/Alafasy_128kbps/049011.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('49:12', 49, 12, 26, 517, 4624, 'يٰٓاَيُّهَا الَّذِيْنَ اٰمَنُوا اجْتَنِبُوْا كَثِيْرًا مِّنَ الظَّنِّۖ اِنَّ بَعْضَ الظَّنِّ اِثْمٌ وَّلَا تَجَسَّسُوْا وَلَا يَغْتَبْ بَّعْضُكُمْ بَعْضًاۗ  اَيُحِبُّ اَحَدُكُمْ اَنْ يَّأْكُلَ لَحْمَ اَخِيْهِ مَيْتًا فَكَرِهْتُمُوْهُۗ وَاتَّقُوا اللّٰهَ ۗاِنَّ اللّٰهَ تَوَّابٌ رَّحِيْمٌ', ' Wahai orang-orang yang beriman, jauhilah banyak prasangka! Sesungguhnya sebagian prasangka itu dosa. Janganlah mencari-cari kesalahan orang lain dan janganlah ada di antara kamu yang menggunjing sebagian yang lain. Apakah ada di antara kamu yang suka memakan daging saudaranya yang sudah mati? Tentu kamu merasa jijik. Bertakwalah kepada Allah! Sesungguhnya Allah Maha Penerima Tobat lagi Maha Penyayang.', '', 'https://everyayah.com/data/Alafasy_128kbps/049012.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('49:13', 49, 13, 26, 517, 4625, 'يٰٓاَيُّهَا النَّاسُ اِنَّا خَلَقْنٰكُمْ مِّنْ ذَكَرٍ وَّاُنْثٰى وَجَعَلْنٰكُمْ شُعُوْبًا وَّقَبَاۤىِٕلَ لِتَعَارَفُوْا ۚ اِنَّ اَكْرَمَكُمْ عِنْدَ اللّٰهِ اَتْقٰىكُمْ ۗاِنَّ اللّٰهَ عَلِيْمٌ خَبِيْرٌ ', ' Wahai manusia, sesungguhnya Kami telah menciptakan kamu dari seorang laki-laki dan perempuan. Kemudian, Kami menjadikan kamu berbangsa-bangsa dan bersuku-suku agar kamu saling mengenal. Sesungguhnya yang paling mulia di antara kamu di sisi Allah adalah orang yang paling bertakwa. Sesungguhnya Allah Maha Mengetahui lagi Maha Teliti. ', '', 'https://everyayah.com/data/Alafasy_128kbps/049013.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('49:14', 49, 14, 26, 517, 4626, '۞ قَالَتِ الْاَعْرَابُ اٰمَنَّا ۗ قُلْ لَّمْ تُؤْمِنُوْا وَلٰكِنْ قُوْلُوْٓا اَسْلَمْنَا وَلَمَّا يَدْخُلِ الْاِيْمَانُ فِيْ قُلُوْبِكُمْ ۗوَاِنْ تُطِيْعُوا اللّٰهَ وَرَسُوْلَهٗ لَا يَلِتْكُمْ مِّنْ اَعْمَالِكُمْ شَيْـًٔا ۗاِنَّ اللّٰهَ غَفُوْرٌ رَّحِيْمٌ ', ' Orang-orang Arab Badui berkata, “Kami telah beriman.” Katakanlah (kepada mereka), “Kamu belum beriman, tetapi katakanlah, ‘Kami baru berislam’ karena iman (yang sebenarnya) belum masuk ke dalam hatimu. Jika kamu taat kepada Allah dan Rasul-Nya, Dia tidak akan mengurangi sedikit pun (pahala) amal perbuatanmu.” Sesungguhnya Allah Maha Pengampun lagi Maha Penyayang. ', '', 'https://everyayah.com/data/Alafasy_128kbps/049014.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('49:15', 49, 15, 26, 517, 4627, 'اِنَّمَا الْمُؤْمِنُوْنَ الَّذِيْنَ اٰمَنُوْا بِاللّٰهِ وَرَسُوْلِهٖ ثُمَّ لَمْ يَرْتَابُوْا وَجَاهَدُوْا بِاَمْوَالِهِمْ وَاَنْفُسِهِمْ فِيْ سَبِيْلِ اللّٰهِ ۗ اُولٰۤىِٕكَ هُمُ الصّٰدِقُوْنَ ', ' Sesungguhnya orang-orang mukmin (yang sebenarnya) hanyalah mereka yang beriman kepada Allah dan Rasul-Nya, kemudian mereka tidak ragu-ragu dan mereka berjihad dengan harta dan jiwanya di jalan Allah. Mereka itulah orang-orang benar.', '', 'https://everyayah.com/data/Alafasy_128kbps/049015.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('49:16', 49, 16, 26, 517, 4628, 'قُلْ اَتُعَلِّمُوْنَ اللّٰهَ بِدِيْنِكُمْۗ وَاللّٰهُ يَعْلَمُ مَا فِى السَّمٰوٰتِ وَمَا فِى الْاَرْضِۗ وَاللّٰهُ بِكُلِّ شَيْءٍ عَلِيْمٌ ', 'Katakanlah (kepada mereka), “Apakah kamu akan memberi tahu Allah tentang agamamu (keyakinanmu), padahal Allah mengetahui apa yang ada di langit dan apa yang ada di bumi serta Allah Maha Mengetahui segala sesuatu.” ', '', 'https://everyayah.com/data/Alafasy_128kbps/049016.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('49:17', 49, 17, 26, 517, 4629, 'يَمُنُّوْنَ عَلَيْكَ اَنْ اَسْلَمُوْا ۗ قُلْ لَّا تَمُنُّوْا عَلَيَّ اِسْلَامَكُمْ ۚبَلِ اللّٰهُ يَمُنُّ عَلَيْكُمْ اَنْ هَدٰىكُمْ لِلْاِيْمَانِ اِنْ كُنْتُمْ صٰدِقِيْنَ ', 'Mereka merasa berjasa kepadamu dengan keislaman mereka. Katakanlah, “Janganlah merasa berjasa kepadaku dengan keislamanmu. Sebenarnya Allahlah yang melimpahkan nikmat kepadamu dengan menunjukkan kamu kepada keimanan, jika kamu orang-orang benar.” ', '', 'https://everyayah.com/data/Alafasy_128kbps/049017.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('49:18', 49, 18, 26, 517, 4630, 'اِنَّ اللّٰهَ يَعْلَمُ غَيْبَ السَّمٰوٰتِ وَالْاَرْضِۗ وَاللّٰهُ بَصِيْرٌۢ بِمَا تَعْمَلُوْنَ ࣖ ', ' Sesungguhnya Allah mengetahui apa yang gaib di langit dan di bumi. Allah Maha Melihat apa yang kamu kerjakan.', '', 'https://everyayah.com/data/Alafasy_128kbps/049018.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:1', 50, 1, 26, 518, 4631, 'قۤ  ۗوَالْقُرْاٰنِ الْمَجِيْدِ  ۖ ', ' Qāf. Demi Al-Qur’an yang mulia.', '', 'https://everyayah.com/data/Alafasy_128kbps/050001.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:2', 50, 2, 26, 518, 4632, 'بَلْ عَجِبُوْٓا اَنْ جَاۤءَهُمْ مُّنْذِرٌ مِّنْهُمْ فَقَالَ الْكٰفِرُوْنَ هٰذَا شَيْءٌ عَجِيْبٌ ۚ', ' (Mereka menolaknya,) bahkan mereka heran karena telah datang kepada mereka seorang pemberi peringatan dari (kalangan) mereka sendiri. Berkatalah orang-orang kafir, “Ini adalah sesuatu yang sangat mengherankan. ', '', 'https://everyayah.com/data/Alafasy_128kbps/050002.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:3', 50, 3, 26, 518, 4633, 'ءَاِذَا مِتْنَا وَكُنَّا تُرَابًا ۚ ذٰلِكَ رَجْعٌۢ بَعِيْدٌ ', ' Apakah setelah kami mati dan sudah menjadi tanah (akan dikembalikan)? Itu adalah pengembalian yang sangat jauh.”', '', 'https://everyayah.com/data/Alafasy_128kbps/050003.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:4', 50, 4, 26, 518, 4634, 'قَدْ عَلِمْنَا مَا تَنْقُصُ الْاَرْضُ مِنْهُمْ ۚوَعِنْدَنَا كِتٰبٌ حَفِيْظٌ ', ' Sungguh, Kami telah mengetahui apa yang dimakan bumi dari (tubuh) mereka karena pada Kami ada kitab (catatan) yang terpelihara baik.', '', 'https://everyayah.com/data/Alafasy_128kbps/050004.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:5', 50, 5, 26, 518, 4635, 'بَلْ كَذَّبُوْا بِالْحَقِّ لَمَّا جَاۤءَهُمْ فَهُمْ فِيْٓ اَمْرٍ مَّرِيْجٍ ', ' Bahkan, mereka mendustakan kebenaran ketika datang kepadanya. Maka, mereka berada dalam keadaan kacau balau. ', '', 'https://everyayah.com/data/Alafasy_128kbps/050005.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:6', 50, 6, 26, 518, 4636, 'اَفَلَمْ يَنْظُرُوْٓا اِلَى السَّمَاۤءِ فَوْقَهُمْ كَيْفَ بَنَيْنٰهَا وَزَيَّنّٰهَا وَمَا لَهَا مِنْ فُرُوْجٍ ', ' Apakah mereka tidak memperhatikan langit yang ada di atas mereka, bagaimana cara Kami membangunnya dan menghiasinya tanpa ada retak-retak padanya sedikit pun? ', '', 'https://everyayah.com/data/Alafasy_128kbps/050006.mp3');
INSERT OR REPLACE INTO ayahs (id, surah_id, ayah_number, juz, page, global_ayah_id, text_ar, translation_id, footnotes, audio_url) VALUES ('50:7', 50, 7, 26, 518, 4637, 'وَالْاَرْضَ مَدَدْنٰهَا وَاَلْقَيْنَا فِيْهَا رَوَاسِيَ وَاَنْۢبَتْنَا فِيْهَا مِنْ كُلِّ زَوْجٍۢ بَهِيْجٍۙ ', ' (Demikian pula) bumi yang Kami hamparkan serta Kami pancangkan di atasnya gunung-gunung yang kukuh dan Kami tumbuhkan di atasnya berbagai jenis (tetumbuhan) yang indah', '', 'https://everyayah.com/data/Alafasy_128kbps/050007.mp3');
PRAGMA foreign_keys = ON;
